    public Long addPagoFactura(final String Id_PeriodoC, final String Id_Liquidacion, final String Id_ConceptoPago, final String FechaAbono, final double Valor, final String UrlSoporte, final String Observacion) {
        GeneratedKeyHolder generatedKeyHolder = new GeneratedKeyHolder();
        this.jdbcTemplate.update(new PreparedStatementCreator() { // from class: com.genoma.plus.dao.impl.gcuenta.GCuentaDAOImpl.6
            public PreparedStatement createPreparedStatement(Connection connection) throws SQLException {
                PreparedStatement ps = connection.prepareStatement("insert into f_factura_pagos(Id_PeriodoC, Id_Liquidacion, Id_ConceptoPago, FechaAbono, Valor, UrlSoporte, Observacion, UsuarioS)     VALUES (?,?,?,?,?,?,?,?)", 1);
                ps.setString(1, Id_PeriodoC);
                ps.setString(2, Id_Liquidacion);
                ps.setString(3, Id_ConceptoPago);
                ps.setString(4, FechaAbono);
                ps.setDouble(5, Valor);
                ps.setString(6, UrlSoporte);
                ps.setString(7, Observacion);
                ps.setString(8, Principal.usuarioSistemaDTO.getLogin());
                return ps;
            }
        }, generatedKeyHolder);
        return Long.valueOf(generatedKeyHolder.getKey().longValue());
    }

