    public List<Object[]> listDocumentosPagoGlobales(String idEmpresa, String nDocumento) {
        RowMapper mapper = new RowMapper() { // from class: com.genoma.plus.dao.impl.gcuenta.GCuentaDAOImpl.8
            public Object mapRow(ResultSet rs, int rowNum) throws SQLException {
                Object[] fila = {Long.valueOf(rs.getLong(1)), rs.getString(2), rs.getString(3), Double.valueOf(rs.getDouble(4)), rs.getString(5)};
                return fila;
            }
        };
        List<Object[]> list = this.jdbcTemplate.query("SELECT\n    `cc_documentoc`.`Id`\n    , DATE_FORMAT(`cc_documentoc`.`FechaD`, '%d-%m-%Y') Fecha\n    , `cc_tipo_documentoc`.`Nbre`\n    , `cc_detalle_documentoc`.`VCredito`   \n    , `cc_documentoc`.`Descripcion`\nFROM\n    `cc_detalle_documentoc`\n    INNER JOIN `cc_documentoc` \n        ON (`cc_detalle_documentoc`.`Id_Documentoc` = `cc_documentoc`.`Id`)\n    INNER JOIN `cc_tipo_documentoc` \n        ON (`cc_documentoc`.`Id_TipoComprobante` = `cc_tipo_documentoc`.`Id`)\nWHERE (`cc_detalle_documentoc`.`VCredito` <>0\n    AND `cc_documentoc`.`EsGlobal` =1\n   AND `cc_documentoc`.`Estado` =1\n    AND `cc_detalle_documentoc`.`Id_Tercero` =? and `cc_documentoc`.`Id`=? ) ORDER BY `cc_documentoc`.`Id` ASC;", mapper, new Object[]{idEmpresa, nDocumento});
        return list;
    }

    public List<Object[]> listDocumentosPagoGlobalesFEmpresa(String idEmpresa, Boolean xFiltro) {
        List<Object[]> list;
        RowMapper mapper = new RowMapper() { // from class: com.genoma.plus.dao.impl.gcuenta.GCuentaDAOImpl.9
            public Object mapRow(ResultSet rs, int rowNum) throws SQLException {
                Object[] fila = {Long.valueOf(rs.getLong(1)), rs.getString(2), rs.getString(3), Double.valueOf(rs.getDouble(4)), rs.getString(5), rs.getString(6)};
                return fila;
            }
        };
        if (xFiltro.booleanValue()) {
            list = this.jdbcTemplate.query("SELECT\n    `cc_documentoc`.`Id`\n    , DATE_FORMAT(`cc_documentoc`.`FechaD`, '%d-%m-%Y') Fecha\n    , `cc_tipo_documentoc`.`Nbre`\n    , `cc_detalle_documentoc`.`VCredito`   \n    , `cc_documentoc`.`Descripcion`, cc_terceros.`RazonSocialCompleta`\nFROM\n    `cc_detalle_documentoc`\n    INNER JOIN `cc_documentoc` \n        ON (`cc_detalle_documentoc`.`Id_Documentoc` = `cc_documentoc`.`Id`)\n    INNER JOIN `cc_tipo_documentoc` \n        ON (`cc_documentoc`.`Id_TipoComprobante` = `cc_tipo_documentoc`.`Id`)\n         INNER JOIN `cc_terceros` \n        ON (cc_terceros.`Id` = `cc_detalle_documentoc`.`Id_Tercero`)\nWHERE (`cc_detalle_documentoc`.`VCredito` <>0\n    AND `cc_documentoc`.`EsGlobal` =1\n    AND `cc_documentoc`.`Estado` =1\n    AND `cc_detalle_documentoc`.`Id_Tercero` =?) ORDER BY `cc_documentoc`.`Id` ASC", mapper, new Object[]{idEmpresa});
        } else {
            list = this.jdbcTemplate.query("SELECT\n    `cc_documentoc`.`Id`\n    , DATE_FORMAT(`cc_documentoc`.`FechaD`, '%d-%m-%Y') Fecha\n    , `cc_tipo_documentoc`.`Nbre`\n    , `cc_detalle_documentoc`.`VCredito`   \n    , `cc_documentoc`.`Descripcion`, cc_terceros.`RazonSocialCompleta`\nFROM\n    `cc_detalle_documentoc`\n    INNER JOIN `cc_documentoc` \n        ON (`cc_detalle_documentoc`.`Id_Documentoc` = `cc_documentoc`.`Id`)\n    INNER JOIN `cc_tipo_documentoc` \n        ON (`cc_documentoc`.`Id_TipoComprobante` = `cc_tipo_documentoc`.`Id`)\n         INNER JOIN `cc_terceros` \n        ON (cc_terceros.`Id` = `cc_detalle_documentoc`.`Id_Tercero`)\nWHERE (`cc_detalle_documentoc`.`VCredito` <>0\n    AND `cc_documentoc`.`EsGlobal` =1\n    AND `cc_documentoc`.`Estado` =1\n   ) ORDER BY cc_terceros.`RazonSocialCompleta` asc, `cc_documentoc`.`Id` ASC", mapper);
        }
        return list;
    }

