    public List<GCCTmpCartera> listadoConsolidadoCarteraC(Integer formaVisualizacion) {
        String sql;
        RowMapper mapper = (rs, rowNum) -> {
            GCCTmpCartera g = new GCCTmpCartera();
            g.setIdTercero(rs.getString("Id"));
            g.setNombreEmpresa(rs.getString("Empresa"));
            g.setValorPorRadicar(rs.getDouble("POR_RADICAR"));
            g.setValorEnProceso(rs.getDouble("EN_PROCESO"));
            g.setValor1_30Dias(rs.getDouble("1_30"));
            g.setValor31_60Dias(rs.getDouble("31_60"));
            g.setValor61_90Dias(rs.getDouble("61_90"));
            g.setValor91_180Dias(rs.getDouble("91_180"));
            g.setValor181_360Dias(rs.getDouble("181_360"));
            g.setValor361_720Dias(rs.getDouble("361_720"));
            g.setValor360Dias_Adelante(rs.getDouble("360_ADELANTE"));
            g.setValor720Dias_Adelante(rs.getDouble("720_ADELANTE"));
            g.setValorTotal(rs.getDouble("TOTAL"));
            g.setNombreRegimen(rs.getString("Regimen"));
            return g;
        };
        if (formaVisualizacion.intValue() == 0) {
            sql = "SELECT\n    `Id`\n    , `Empresa`\n    , `POR_RADICAR`\n    , `EN_PROCESO`\n    , `1_30`\n    , `31_60`\n    , `61_90`\n    , `91_180`\n    , `181_360`\n    , `361_720`\n    , `360_ADELANTE`, `720_ADELANTE`,TOTAL , Regimen\nFROM\n   `f_tmp_cartera`";
        } else {
            sql = "SELECT\n    `Id`\n    , `Empresa`\n    , `POR_RADICAR`\n    , `EN_PROCESO`\n    , `1_30`\n    , `31_60`\n    , `61_90`\n    , `91_180`\n    , `181_360`\n    , `361_720`\n    , `360_ADELANTE`, `720_ADELANTE`,TOTAL , Regimen\nFROM\n   `f_tmp_cartera` ORDER BY Regimen ASC";
        }
        List<GCCTmpCartera> list = this.jdbcTemplate.query(sql, mapper);
        return list;
    }

