    public void listadoConsolidadoCarteraTmp(String xFechaInicio, String xFechaCorte, String xIdEmpresa, Boolean forma) {
        this.jdbcTemplate.update("TRUNCATE TABLE f_tmp_cartera");
        String sql = "INSERT INTO f_tmp_cartera \nWITH cartera_facturacion AS (\nSELECT f_liquidacion.Id IdLiquidacion\n, cc_terceros.No_identificacion as idEmpresa\n, cc_terceros.RazonSocialCompleta NEmpresa\n, f_empresacontxconvenio.Id Id_convenio\n, f_empresacontxconvenio.Nbre AS Convenio \n, DATE_FORMAT(f_factura_evento.Fecha_FacturaEvento,'%d-%m-%Y') AS FFactura \n, IF ( `cc_resolucion_dian`.`trasmision`= 0 ,IF(f_factura_evento.Prefijo='',f_factura_evento.No_FacturaEvento ,CONCAT(f_factura_evento.Prefijo,'',f_factura_evento.No_FacturaEvento)), IF(f_factura_evento.Prefijo='',f_factura_evento.`No_FacturaEvento_M` ,CONCAT(f_factura_evento.Prefijo,'',f_factura_evento.`No_FacturaEvento_M`)))  AS NFactura \n, f_subgruposervicio.Nbre AS NServicio \n, ROUND(f_liquidacion.TotalServicio) AS TotalServicio\n, ROUND(f_liquidacion.TotalDescuento) AS TotalDescuento\n, ROUND(f_liquidacion.CuotaModeradora) AS TotalCModeradora\n, ROUND(f_liquidacion.Copago) AS TotalCopago\n, ROUND(IF(f_liquidacion.TotalEps=0, f_liquidacion.TotalPaciente, f_liquidacion.TotalEps)) AS VTotal\n, IF(f_factura_evento.FechaEntrega IS NULL, FALSE, TRUE) AS Radicado \n, CASE \tWHEN f_factura_evento.FechaRadicado IS NULL THEN 0\n  ELSE \n\tCASE WHEN f_factura_evento.FechaRadicado>'" + xFechaCorte + "' THEN 0\n\tELSE 1\n  END\t\n\n  END NRadicado\n-- , IF(f_factura_evento.NRadicado ='', 0, 1) NRadicado\n, IF(f_factura_evento.FechaEntrega IS NULL, '' ,DATE_FORMAT(f_factura_evento.FechaEntrega,'%d-%m-%Y')) AS FEntrega \n, IF(f_factura_evento.FechaRadicado IS NULL, '' ,DATE_FORMAT(f_factura_evento.FechaRadicado,'%d-%m-%Y')) AS FRAdicado \n, IF(f_liquidacion.FechaUltimoPago IS NULL, '' ,DATE_FORMAT(f_liquidacion.FechaUltimoPago,'%d-%m-%Y')) AS FechaUP \n, f_factura_evento.No_CuentaCobro\n, f_factura_evento.UrlRadicado\n, g_etapa_proceso.Nbre NEtapaProceso\n, f_tiporegimen.Nbre AS Regimen\n, f_empresacontxconvenio.NDiasP\n, f_factura_evento.FechaRadicado\n, IF(f_factura_evento.ObservacionRad IS NULL, '', f_factura_evento.ObservacionRad) AS CRad \n, f_factura_evento.CJuridico\n, g_ips.Nbre NIps\n, f_subgrupo_empresa.CPuc_Credito_R\n, f_subgrupo_empresa.CPuc_Debito_R\n, cc_terceros.Id AS Id_empresa\n, f_factura_evento.Id_DocumentoCR \n, f_subgrupo_empresa.CPuc_Debito_G\n, f_subgrupo_empresa.CPuc_Credito_G\n, IFNULL(f_subgrupo_empresa.CPuc_Debito_GS,'') AS CPuc_Debito_GS\n, IFNULL(f_subgrupo_empresa.CPuc_Credito_GS,'') AS CPuc_Credito_GS\n, f_subgrupo_empresa.CPuc_Debito_D \n, f_subgrupo_empresa.CPuc_Credito_D, IFNULL(`f_subgrupo_empresa`.CPuc_Credito,'') AS CPuc_Credito , IFNULL(`f_subgrupo_empresa`.`IdRubro`,'') AS IdRubroP, IFNULL(f_factura_evento.`Id_DocumentoC`,0) AS IdDocumentoC , cc_documentoc.`FechaD`\nFROM f_factura_evento\nINNER JOIN f_liquidacion \nON (f_factura_evento.Id_Liquidacion = f_liquidacion.Id)\nINNER JOIN f_empresacontxconvenio \nON (f_liquidacion.IdEmpresaContxConv = f_empresacontxconvenio.Id)\nINNER JOIN g_empresacont \nON (f_empresacontxconvenio.Id_EmpresaCont = g_empresacont.Id_empresa) \nINNER JOIN f_tiporegimen \nON (f_empresacontxconvenio.Id_TipoRegimen = f_tiporegimen.Id)\nINNER JOIN cc_terceros \nON (cc_terceros.Id = g_empresacont.Id_empresa)\nINNER JOIN f_subgrupo_empresa \nON (f_liquidacion.Id_SubGrupoServicio = f_subgrupo_empresa.Id) \nINNER JOIN f_subgruposervicio \nON (f_subgrupo_empresa.Id_SubGrupo = f_subgruposervicio.Id_SubgrupoServicio) \nINNER JOIN f_gruposervicio \nON (f_subgruposervicio.Id_GrupoServicio = f_gruposervicio.Id_GrupoServicio) \nINNER JOIN g_etapa_proceso \nON (f_factura_evento.IdEtapaProcedo = g_etapa_proceso.Id)\n                                  inner join f_cuentacobro on(f_cuentacobro.NoCuenta=f_factura_evento.No_CuentaCobro)\n                                                         inner join cc_periodo_contable on (cc_periodo_contable.Id=f_cuentacobro.Id_PeriodoC)  INNER JOIN g_ips \nON (f_empresacontxconvenio.Id_GIps = g_ips.Id)\nLEFT JOIN `cc_documentoc` ON (cc_documentoc.`Id` = f_factura_evento.`Id_DocumentoC`) AND (cc_documentoc.`Estado`=1) \n INNER JOIN `cc_resolucion_dian` ON( `cc_resolucion_dian`.`Id` = `f_factura_evento`.`idResolucionDian`) WHERE (if(1=" + forma + ",f_factura_evento.Fecha_FacturaEvento,cc_periodo_contable.FechaI) >='" + xFechaInicio + "'\nAND if(1=" + forma + ",f_factura_evento.Fecha_FacturaEvento,cc_periodo_contable.FechaI) <='" + xFechaCorte + "'\n";
        if (!xIdEmpresa.isEmpty() && !xIdEmpresa.equals("-1")) {
            sql = sql + "AND cc_terceros.id = '" + xIdEmpresa + "' ";
        }
        String sql2 = sql + "AND f_liquidacion.Estado =0\nAND f_factura_evento.Estado =0\nAND f_factura_evento.EstaArmada =2 AND cc_terceros.EsManejoC=1)\n)\n\n -- select * from cartera_facturacion where NRadicado=1;\n\n, cartera_glosas AS (\n\nSELECT f_factura_glosa.Id_Liquidacion IdLiquidacion, ROUND(SUM(f_factura_glosa.Valor)) AS VGlosado\nFROM f_factura_glosa INNER JOIN `f_tipoconcepto_pago` ON (`f_factura_glosa`.`Id_ConceptoG` = `f_tipoconcepto_pago`.`Id`)\nWHERE (f_factura_glosa.Estado=1 and f_factura_glosa.EsReiterada=0) AND (f_factura_glosa.FechaG<='" + xFechaCorte + "' AND `f_tipoconcepto_pago`.`Tipo` <>2)\nGROUP BY f_factura_glosa.Id_Liquidacion\n)\n\n, cartera_resp_glosas AS (\nSELECT Id_Liquidacion IdLiquidacion, ROUND(SUM(f_factura_glosa_respuesta.ValorA)) AS VAceptado, ROUND(SUM(f_factura_glosa_respuesta.ValorR)) AS VRecuperable\nFROM f_factura_glosa\nINNER JOIN f_factura_glosa_respuesta \nON (f_factura_glosa_respuesta.Id_Factura_glosa = f_factura_glosa.Id) INNER JOIN `f_tipoconcepto_pago` ON (`f_factura_glosa`.`Id_ConceptoG` = `f_tipoconcepto_pago`.`Id`)\nWHERE (f_factura_glosa.Estado=1 and f_factura_glosa.EsReiterada=0) AND (f_factura_glosa.FechaG<='" + xFechaCorte + "') AND (f_factura_glosa_respuesta.Estado=1) AND `f_tipoconcepto_pago`.`Tipo` <>2 \nAND (DATE_FORMAT(f_factura_glosa_respuesta.Fecha, '%Y-%m-%d')<='" + xFechaCorte + "') \nGROUP BY Id_Liquidacion\n)\n\n\n,cartera_pagos AS (\nSELECT Id_Liquidacion IdLiquidacion , ROUND(SUM(f_factura_pagos.Valor)) AS VPagado \nFROM f_factura_pagos \nWHERE (f_factura_pagos.Estado=1) AND (f_factura_pagos.FechaAbono<='" + xFechaCorte + "')\nGROUP BY Id_Liquidacion\n)\n\n\n,consolidado_cartera AS ( \n\nSELECT d.idEmpresa AS Id_empresa, IF(d.NEmpresa= '', d.Convenio,d.NEmpresa) NEmpresa\n, d.NRadicado AS Radicado\n, IF(((d.VTotal- IFNULL(g.VAceptado,0))-IFNULL(p.VPagado,0) )<=0 ,0, IF(d.FechaRadicado IS NULL,0, IF(DATEDIFF('" + xFechaCorte + "', DATE_ADD(d.FechaRadicado, INTERVAL d.NDiasP DAY))<0,0,DATEDIFF('" + xFechaCorte + "', DATE_ADD(d.FechaRadicado, INTERVAL d.NDiasP DAY)) ) )) AS NDias\n, ((d.VTotal- IFNULL(g.VAceptado,0))-IFNULL(p.VPagado,0) )Saldo \n, d.Regimen\nFROM cartera_facturacion d\nLEFT JOIN cartera_glosas f\nON d.IdLiquidacion=f.IdLiquidacion\nLEFT JOIN cartera_resp_glosas g\nON d.IdLiquidacion=g.IdLiquidacion\nLEFT JOIN cartera_pagos p\nON d.IdLiquidacion=p.IdLiquidacion\n\nHAVING saldo<>0\nORDER BY d.NEmpresa ASC, d.Convenio ASC\n)\n\n-- select * from consolidado_cartera;\n\n, sumatoria_cartera AS (\nSELECT \nn.Id_empresa\n,n.NEmpresa \n,n.Radicado\n,n.NDias\n,SUM(n.Saldo) Saldo, n.Regimen\nFROM consolidado_cartera n\nGROUP BY n.Id_empresa, n.Radicado, n.NDias\n)\n, cartera_dias AS (\nSELECT \nf.Id_empresa\n,f.NEmpresa , f.NDias\n, IF(f.Radicado=0, f.Saldo, 0) POR_RADICAR\n, IF( (f.Radicado=1 AND (f.NDias=0)) , f.Saldo, 0) EN_PROCESO\n, IF( (f.Radicado=1 AND (f.NDias>0 AND f.NDias<=30)) , f.Saldo, 0) 1_30\n, IF( (f.Radicado=1 AND (f.NDias>30 AND f.NDias<=60)) , f.Saldo, 0) 31_60\n, IF( (f.Radicado=1 AND (f.NDias>60 AND f.NDias<=90)) , f.Saldo, 0) 61_90\n, IF( (f.Radicado=1 AND (f.NDias>90 AND f.NDias<=180)) , f.Saldo, 0) 91_180\n, IF( (f.Radicado=1 AND (f.NDias>180 AND f.NDias<=360)) , f.Saldo, 0) 181_360\n, IF( (f.Radicado=1 AND (f.NDias>360 AND f.NDias<=720)) , f.Saldo, 0) 361_720\n, IF( (f.Radicado=1 AND (f.NDias>360)) , f.Saldo, 0) 360_ADELANTE\n, IF( (f.Radicado=1 AND (f.NDias>720)) , f.Saldo, 0) 720_ADELANTE\n, f.Saldo Total, f.Regimen \nFROM sumatoria_cartera f\n\n)\n\nSELECT \nG.Id_empresa\n,G.NEmpresa\n,SUM(G.POR_RADICAR) POR_RADICAR\n,SUM(G.EN_PROCESO) EN_PROCESO\n,SUM(G.1_30) 1_30\n,SUM(G.31_60) 31_60\n,SUM(G.61_90) 61_90\n,SUM(G.91_180) 91_180\n,SUM(G.181_360) 181_360\n,SUM(G.361_720) 361_720\n,SUM(G.360_ADELANTE) 360_ADELANTE\n,SUM(G.720_ADELANTE) 720_ADELANTE\n,SUM(Total) Total, G.Regimen\nFROM cartera_dias G\nGROUP BY G.Id_empresa\nORDER BY G.NEmpresa";
        System.out.println("Consuolidado " + sql2);
        this.jdbcTemplate.update(sql2);
    }

