                    sql = "SELECT\n  d.FFactura,\n  d.NFactura,\n  d.NServicio,\n  d.TotalServicio,\n  d.TotalDescuento,\n  d.TotalCModeradora,\n  d.TotalCopago,\n  d.VTotal,\n  d.Radicado,\n  d.NRadicado,\n  d.FEntrega,\n  d.FRAdicado,\n  d.IdLiquidacion,\n  d.CRad,\n  (\n    (d.VTotal - IFNULL(r.VAceptado, 0)) - IFNULL(p.VPagado, 0)\n  ) Saldo,\n  IFNULL(p.VPagado, 0) VPagado,\n  IFNULL(f.VGlosado, 0) VGlosado,\n  IFNULL(g.VRecuperable, 0) VRecuperable,\n  IFNULL(r.VAceptado, 0) VAceptado,\n  d.FechaUP,\n  IF(\n    (\n      (d.VTotal - IFNULL(r.VAceptado, 0)) - IFNULL(p.VPagado, 0)\n    ) <= 0,\n    0,\n    IF(\n      d.FechaRadicado IS NULL,\n      0,\n      IF(\n        DATEDIFF(\n          NOW(),\n          DATE_ADD(\n            d.FechaRadicado,\n            INTERVAL d.NDiasP DAY\n          )\n        ) < 0,\n        0,\n        DATEDIFF(\n          NOW(),\n          DATE_ADD(\n            d.FechaRadicado,\n            INTERVAL d.NDiasP DAY\n          )\n        )\n      )\n    )\n  ) AS NDias,\n  d.FRAdicado NFecha,\n  IF(\n    d.NEmpresa = '',\n    d.Convenio,\n    d.NEmpresa\n  ) NEmpresa,\n  d.No_CuentaCobro,\n  d.UrlRadicado,\n  d.CJuridico,\n  d.NEtapaProceso,\n  d.NIps,\n  d.CPuc_Credito_R,\n  d.CPuc_Debito_R,\n  d.Id_empresa,\n  d.Id_DocumentoCR,\n  d.CPuc_Debito_G,\n  d.CPuc_Credito_G,\n  d.CPuc_Debito_GS,\n  d.CPuc_Credito_GS,\n  d.Regimen,\n  d.CPuc_Debito_D,\n  d.CPuc_Credito_D,\n  d.Convenio,\n  d.CPuc_Credito,\n  d.IdRubroP,\n  d.IdDocumentoC,\n  d.FechaD,\n  d.`Id_Ingreso`,\n  d.No_FacturaEvento,\n  d.`EsCapitado`,\n  d.trasmision\nFROM\n  -- tmp_cartera_facturacion \n   (SELECT\n    f_liquidacion.Id IdLiquidacion,\n    cc_terceros.Id,\n    cc_terceros.RazonSocialCompleta NEmpresa,\n    f_empresacontxconvenio.Id Id_convenio,\n    f_empresacontxconvenio.Nbre AS Convenio,\n    DATE_FORMAT(\n      f_factura_evento.Fecha_FacturaEvento,\n      '%d-%m-%Y'\n    ) AS FFactura,\n    IF (\n      `cc_resolucion_dian`.`trasmision` = 0,\n      IF(\n        f_factura_evento.Prefijo = '',\n        f_factura_evento.No_FacturaEvento,\n        CONCAT(\n          f_factura_evento.Prefijo,\n          '',\n          f_factura_evento.No_FacturaEvento\n        )\n      ),\n      IF(\n        f_factura_evento.Prefijo = '',\n        f_factura_evento.`No_FacturaEvento_M`,\n        CONCAT(\n          f_factura_evento.Prefijo,\n          '',\n          f_factura_evento.`No_FacturaEvento_M`\n        )\n      )\n    ) AS NFactura,\n    f_subgruposervicio.Nbre AS NServicio,\n    ROUND(f_liquidacion.TotalServicio) AS TotalServicio,\n    ROUND(f_liquidacion.TotalDescuento) AS TotalDescuento,\n    ROUND(f_liquidacion.CuotaModeradora) AS TotalCModeradora,\n    ROUND(f_liquidacion.Copago) AS TotalCopago,\n    ROUND(\n      IF(\n        f_liquidacion.TotalEps = 0,\n        f_liquidacion.TotalPaciente,\n        f_liquidacion.TotalEps\n      )\n    ) AS VTotal,\n    IF(\n      f_factura_evento.FechaEntrega IS NULL,\n      FALSE,\n      TRUE\n    ) AS Radicado,\n    f_factura_evento.NRadicado,\n    IF(\n      f_factura_evento.FechaEntrega IS NULL,\n      '',\n      DATE_FORMAT(\n        f_factura_evento.FechaEntrega,\n        '%d-%m-%Y'\n      )\n    ) AS FEntrega,\n    IF(\n      f_factura_evento.FechaRadicado IS NULL,\n      '',\n      DATE_FORMAT(\n        f_factura_evento.FechaRadicado,\n        '%d-%m-%Y'\n      )\n    ) AS FRAdicado,\n    IF(\n      f_liquidacion.FechaUltimoPago IS NULL,\n      '',\n      DATE_FORMAT(\n        f_liquidacion.FechaUltimoPago,\n        '%d-%m-%Y'\n      )\n    ) AS FechaUP,\n    f_factura_evento.No_CuentaCobro,\n    f_factura_evento.UrlRadicado,\n    g_etapa_proceso.Nbre NEtapaProceso,\n    f_tiporegimen.Nbre Regimen,\n    f_empresacontxconvenio.NDiasP,\n    f_factura_evento.FechaRadicado,\n    IF(\n      f_factura_evento.ObservacionRad IS NULL,\n      '',\n      f_factura_evento.ObservacionRad\n    ) AS CRad,\n    f_factura_evento.CJuridico,\n    g_ips.Nbre NIps,\n    f_subgrupo_empresa.CPuc_Credito_R,\n    f_subgrupo_empresa.CPuc_Debito_R,\n    cc_terceros.Id AS Id_empresa,\n    f_factura_evento.Id_DocumentoCR,\n    f_subgrupo_empresa.CPuc_Debito_G,\n    f_subgrupo_empresa.CPuc_Credito_G,\n    IFNULL(\n      f_subgrupo_empresa.CPuc_Debito_GS,\n      ''\n    ) AS CPuc_Debito_GS,\n    IFNULL(\n      f_subgrupo_empresa.CPuc_Credito_GS,\n      ''\n    ) AS CPuc_Credito_GS,\n    f_subgrupo_empresa.CPuc_Debito_D,\n    f_subgrupo_empresa.CPuc_Credito_D,\n    IFNULL(\n      `f_subgrupo_empresa`.CPuc_Credito,\n      ''\n    ) AS CPuc_Credito,\n    IFNULL(\n      `f_subgrupo_empresa`.`IdRubro`,\n      ''\n    ) AS IdRubroP,\n    IFNULL(\n      f_factura_evento.`Id_DocumentoC`,\n      0\n    ) AS IdDocumentoC,\n    cc_documentoc.`FechaD`,\n    `f_liquidacion`.`Id_Ingreso`,\n    f_factura_evento.No_FacturaEvento,\n    f_empresacontxconvenio.`EsCapitado`,\n    crd.trasmision\n  FROM\n    f_factura_evento\n    INNER JOIN f_liquidacion\n      ON (\n        f_factura_evento.Id_Liquidacion = f_liquidacion.Id\n      )\n    INNER JOIN cc_resolucion_dian crd\n      ON (\n        crd.Id = f_factura_evento.idResolucionDian\n      )\n    INNER JOIN f_empresacontxconvenio\n      ON (\n        f_liquidacion.IdEmpresaContxConv = f_empresacontxconvenio.Id\n      )\n    INNER JOIN g_empresacont\n      ON (\n        f_empresacontxconvenio.Id_EmpresaCont = g_empresacont.Id_empresa\n      )\n    INNER JOIN f_tiporegimen\n      ON (\n        f_empresacontxconvenio.Id_TipoRegimen = f_tiporegimen.Id\n      )\n    INNER JOIN cc_terceros\n      ON (\n        cc_terceros.Id = g_empresacont.Id_empresa\n      )\n    INNER JOIN f_subgrupo_empresa\n      ON (\n        f_liquidacion.Id_SubGrupoServicio = f_subgrupo_empresa.Id\n      )\n    INNER JOIN f_subgruposervicio\n      ON (\n        f_subgrupo_empresa.Id_SubGrupo = f_subgruposervicio.Id_SubgrupoServicio\n      )\n    INNER JOIN f_gruposervicio\n      ON (\n        f_subgruposervicio.Id_GrupoServicio = f_gruposervicio.Id_GrupoServicio\n      )\n    INNER JOIN g_etapa_proceso\n      ON (\n        f_factura_evento.IdEtapaProcedo = g_etapa_proceso.Id\n      )\n    INNER JOIN g_ips\n      ON (\n        f_empresacontxconvenio.Id_GIps = g_ips.Id\n      )\n    LEFT JOIN `cc_documentoc`\n      ON (\n        cc_documentoc.`Id` = f_factura_evento.`Id_DocumentoC`\n      )\n      AND (cc_documentoc.`Estado` = 1)\n    INNER JOIN `cc_resolucion_dian`\n      ON (\n        `cc_resolucion_dian`.`Id` = `f_factura_evento`.`idResolucionDian`\n      )\n  WHERE (\n      f_factura_evento.Fecha_FacturaEvento >= '" + xFechaI + "'\n      AND f_factura_evento.Fecha_FacturaEvento <= '" + xFechaF + "'\n      AND f_liquidacion.Estado = 0\n      AND f_factura_evento.Estado = 0\n      AND f_factura_evento.EstaArmada = 2\n      AND cc_terceros.EsManejoC = 1\n    )) AS d -- tmp_cartera_glosas\n   LEFT JOIN\n    (SELECT\n      f_factura_glosa.Id_Liquidacion IdLiquidacion,\n      ROUND(SUM(f_factura_glosa.Valor)) AS VGlosado\n    FROM\n      f_factura_glosa\n      INNER JOIN `f_tipoconcepto_pago`\n        ON (\n          `f_factura_glosa`.`Id_ConceptoG` = `f_tipoconcepto_pago`.`Id`\n        )\n    WHERE (\n        f_factura_glosa.Estado = 1\n        AND f_factura_glosa.EsReiterada=0 \n      )\n      AND (\n        f_factura_glosa.FechaG <= '" + xFechaF + "'\n        AND `f_tipoconcepto_pago`.`Tipo` <> 2\n      )\n    GROUP BY f_factura_glosa.Id_Liquidacion) AS f\n    ON d.IdLiquidacion = f.IdLiquidacion -- tmp_cartera_resp_glosas\n   LEFT JOIN\n    (SELECT\n      Id_Liquidacion IdLiquidacion,\n      ROUND(\n        SUM(\n          f_factura_glosa_respuesta.ValorA\n        )\n      ) AS VAceptado,\n      ROUND(\n        SUM(\n          f_factura_glosa_respuesta.ValorR\n        )\n      ) AS VRecuperable\n    FROM\n      f_factura_glosa\n      INNER JOIN f_factura_glosa_respuesta\n        ON (\n          f_factura_glosa_respuesta.Id_Factura_glosa = f_factura_glosa.Id\n        )\n      INNER JOIN `f_tipoconcepto_pago`\n        ON (\n          `f_factura_glosa`.`Id_ConceptoG` = `f_tipoconcepto_pago`.`Id`\n        )\n    WHERE (\n        f_factura_glosa.Estado = 1\n        AND f_factura_glosa.EsReiterada=0 \n      )\n      AND (f_factura_glosa.FechaG <= '')\n      AND (\n        f_factura_glosa_respuesta.Estado = 1\n      )\n      AND `f_tipoconcepto_pago`.`Tipo` <> 2\n      AND (\n        DATE_FORMAT(\n          f_factura_glosa_respuesta.Fecha,\n          '%Y-%m-%d'\n        ) <= '" + xFechaF + "'\n      )\n    GROUP BY Id_Liquidacion) AS g\n    ON d.IdLiquidacion = g.IdLiquidacion -- tmp_cartera_pagos \n   LEFT JOIN\n    (SELECT\n      Id_Liquidacion IdLiquidacion,\n      ROUND(\n        SUM(\n          f_factura_glosa_respuesta.ValorA\n        )\n      ) AS VAceptado\n    FROM\n      f_factura_glosa\n      INNER JOIN f_factura_glosa_respuesta\n        ON (\n          f_factura_glosa_respuesta.Id_Factura_glosa = f_factura_glosa.Id\n        )\n      INNER JOIN `f_tipoconcepto_pago`\n        ON (\n          `f_factura_glosa`.`Id_ConceptoG` = `f_tipoconcepto_pago`.`Id`\n        )\n    WHERE (f_factura_glosa.Estado = 1)\n      AND (\n        f_factura_glosa.FechaG <= '" + xFechaF + "'\n      )\n      AND (\n        f_factura_glosa_respuesta.Estado = 1\n      )\n      AND `f_tipoconcepto_pago`.`Tipo` <> 2\n      AND (\n        DATE_FORMAT(\n          f_factura_glosa_respuesta.Fecha,\n          '%Y-%m-%d'\n        ) <= '2023-03-02'\n      )\n    GROUP BY Id_Liquidacion) AS r\n    ON d.IdLiquidacion = r.IdLiquidacion -- tmp_cartera_pagos\n   LEFT JOIN\n    (SELECT\n      Id_Liquidacion IdLiquidacion,\n      ROUND(SUM(f_factura_pagos.Valor)) AS VPagado\n    FROM\n      f_factura_pagos\n    WHERE (f_factura_pagos.Estado = 1)\n      AND (\n        f_factura_pagos.FechaAbono <= '" + xFechaF + "'\n      )\n    GROUP BY Id_Liquidacion) AS p\n    ON d.IdLiquidacion = p.IdLiquidacion\nORDER BY d.`NFactura` ASC";
