    public List<Object[]> listFacturaOrdenParaRips(String idEmpresaConvenio, String fechaInicio, String fechaFin, int TipoFactura) {
        RowMapper mapper = new RowMapper() { // from class: com.genoma.plus.dao.impl.gcuenta.GCuentaDAOImpl.17
            public Object mapRow(ResultSet rs, int rowNum) throws SQLException {
                Object[] fila = {Boolean.valueOf(rs.getBoolean("seleccionar")), rs.getString("NumeroOrdenFactura"), rs.getString("FechaOrdenFactura"), rs.getString("nombreServicio"), Double.valueOf(rs.getDouble("Valor"))};
                return fila;
            }
        };
        String sql = "";
        if (TipoFactura == 0) {
            sql = "   \n   SELECT FALSE seleccionar, \n     IF(d.Prefijo='',d.`No_FacturaEvento_M` ,CONCAT(d.Prefijo,'',d.`No_FacturaEvento_M`) ) AS `NumeroOrdenFactura`\n    ,  IF( `d`.`Fecha_FacturaEvento` IS NULL, d.`Fecha_FacturaEvento`, `d`.`Fecha_FacturaEvento` )  AS `FechaOrdenFactura`\n    , `f_subgruposervicio`.`Nbre` AS `nombreServicio`\n    , l.`TotalEps` AS `Valor`\n    , ingreso.`Id_EmpresaContxConv` \n    , IFNULL(f_factura_evento.`EstaArmada`, 0)  \n    , IFNULL(f_factura_capita.`EstaArmada`,0)\n    ,  (IFNULL(f_factura_evento.`EstaArmada`, 0) +IFNULL(f_factura_capita.`EstaArmada`,0)) estadoArmada\n    , d.`No_FacturaEvento`\nFROM\n     `f_liquidacion`\n    INNER JOIN  `f_subgrupo_empresa` \n        ON (`f_liquidacion`.`Id_SubGrupoServicio` = `f_subgrupo_empresa`.`Id`)\n    INNER JOIN  `f_subgruposervicio`    ON (`f_subgrupo_empresa`.`Id_SubGrupo` = `f_subgruposervicio`.`Id_SubgrupoServicio`)\n    INNER JOIN  `ingreso`  ON (`ingreso`.`Id` = `f_liquidacion`.`Id_Ingreso`) AND (f_liquidacion.`Estado`=0)\n    LEFT JOIN  `f_factura_evento` ON (`f_factura_evento`.`Id_Liquidacion` = `f_liquidacion`.`Id`)  AND (f_factura_evento.`Estado`=0) \n    LEFT JOIN  `f_factura_capita` ON (`f_factura_capita`.`Id_Liquidacion` = `f_liquidacion`.`Id`) AND (f_factura_capita.`Estado`=0)\n   LEFT JOIN      f_factura_evento d ON (d.`No_FacturaEvento`=f_factura_capita.`No_FacturaEvento`) \n    LEFT JOIN    f_liquidacion l ON  (d.`Id_Liquidacion`=l.`Id`)\n   JOIN `cc_resolucion_dian` ON( `cc_resolucion_dian`.`Id` = `f_factura_evento`.`idResolucionDian`)      WHERE ingreso.`Id_EmpresaContxConv` IN (" + idEmpresaConvenio + ")  AND IF( `f_factura_evento`.`Fecha_FacturaEvento` IS NULL, d.`Fecha_FacturaEvento`, `f_factura_evento`.`Fecha_FacturaEvento` ) BETWEEN '" + fechaInicio + "' AND '" + fechaFin + "' \nGROUP BY NumeroOrdenFactura\nHAVING   estadoArmada=2  \nORDER BY NumeroOrdenFactura DESC";
        } else if (TipoFactura == 1) {
            sql = "SELECT FALSE seleccionar, \n     IF(d.Prefijo='',f_factura_evento.`No_FacturaEvento_M` ,CONCAT(f_factura_evento.Prefijo,'',f_factura_evento.`No_FacturaEvento_M`) ) AS `NumeroOrdenFactura`\n    ,  IF( `f_factura_evento`.`Fecha_FacturaEvento` IS NULL, f_factura_evento.`Fecha_FacturaEvento`, `f_factura_evento`.`Fecha_FacturaEvento` )  AS `FechaOrdenFactura`\n    , `f_subgruposervicio`.`Nbre` AS `nombreServicio`\n    , `f_liquidacion`.`TotalEps` AS `Valor`\n    , ingreso.`Id_EmpresaContxConv` \n    , IFNULL(f_factura_evento.`EstaArmada`, 0)  \n    , IFNULL(f_factura_capita.`EstaArmada`,0)\n    ,  (IFNULL(f_factura_evento.`EstaArmada`, 0) +IFNULL(f_factura_capita.`EstaArmada`,0)) estadoArmada\n    , d.`No_FacturaEvento`\nFROM\n     `f_liquidacion`\n    INNER JOIN  `f_subgrupo_empresa` \n        ON (`f_liquidacion`.`Id_SubGrupoServicio` = `f_subgrupo_empresa`.`Id`)\n    INNER JOIN  `f_subgruposervicio` \n        ON (`f_subgrupo_empresa`.`Id_SubGrupo` = `f_subgruposervicio`.`Id_SubgrupoServicio`)\n    INNER JOIN  `ingreso` \n        ON (`ingreso`.`Id` = `f_liquidacion`.`Id_Ingreso`) AND (f_liquidacion.`Estado`=0)\n    LEFT JOIN  `f_factura_evento` \n        ON (`f_factura_evento`.`Id_Liquidacion` = `f_liquidacion`.`Id`)  AND (f_factura_evento.`Estado`=0) \n    LEFT JOIN  `f_factura_capita` \n        ON (`f_factura_capita`.`Id_Liquidacion` = `f_liquidacion`.`Id`) AND (f_factura_capita.`Estado`=0)\n   LEFT JOIN      f_factura_evento d ON (d.`No_FacturaEvento`=f_factura_capita.`No_FacturaEvento`) \n  INNER JOIN `cc_resolucion_dian` ON( `cc_resolucion_dian`.`Id` = `f_factura_evento`.`idResolucionDian`)    WHERE ingreso.`Id_EmpresaContxConv` IN (" + idEmpresaConvenio + ")  and IF( `f_factura_evento`.`Fecha_FacturaEvento` IS NULL, d.`Fecha_FacturaEvento`, `f_factura_evento`.`Fecha_FacturaEvento` ) Between '" + fechaInicio + "' and '" + fechaFin + "' \nGROUP BY NumeroOrdenFactura\nHAVING   estadoArmada=2  \nORDER BY NumeroOrdenFactura DESC";
            System.err.println("sql" + sql);
        }
        List<Object[]> list = this.jdbcTemplate.query(sql, mapper);
        return list;
    }

